INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-acfc4025-moex-00511', 'elementary-acfc4025', 'elementary-acfc4025-moex-112-34c7f7f6', 'sub-elementary-acfc4025-02', NULL, 'single_choice', '「楷書是字體中最整齊、最嚴謹的形式，唐人在書法上最大成就當屬『楷法』的創立，『法』 是法則、規律，從此以後，中國文字不再演化新的字體。唐以前的楷書是在追求一種法則下 進展的，三國時代的楷書仍帶有行書和隸書的筆勢，南朝楷書更加工整，但行書意味仍然濃 厚。北朝的魏碑體式多樣化，卻尚未尋找出它的規律性，隋代混同南北，成為唐楷的先驅。」 根據上文，下列選項正確的是：', '["唐人書法最大的特色是有書寫法則可以依循", "楷書的整齊嚴謹使它不得帶有行書隸書筆勢", "三國時代流行行書和隸書且沒有成熟的楷書", "南北朝楷書找到書寫規律性故表現趨勢一致 隋代能成為唐楷先驅是因其承襲南北朝發展"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:26+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "513", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00512', 'elementary-acfc4025', 'elementary-acfc4025-moex-112-34c7f7f6', 'sub-elementary-acfc4025-02', NULL, 'single_choice', '「日子就這樣過去，消磨在管山管水裡。並不固執要去做什麼事，然而想來也沒什麼大後悔。 晚上入睡前，閉目感受周遭的寧靜，我總是心懷感激。大自然如此渺漠，卻又如此可親，和 我息息相關；我無法也不願割離。在黑暗中，我彷彿聽到了宇宙生命的呼吸和訓諭。我凝神 諦聽。時間緩緩流過。」 根據上文，下列選項符合文意的是：', '["抒發時光易逝的心中感慨", "顯露對於宇宙浩瀚的迷茫", "敘寫山居歲月的恬淡安然", "呈現離群索居的寂寞孤獨 表達對自然的敬畏與戀慕"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:26+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "513", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00513', 'elementary-acfc4025', 'elementary-acfc4025-moex-112-34c7f7f6', 'sub-elementary-acfc4025-02', NULL, 'single_choice', '有位法國哲人為人道主義下定義：「一個人於河中快淹死，一百個人跳下河中相救，這一百 個人也許會因而淹死，而仍救不上那個人來。以一百比一，是件不理智的行動，我們把這種 行動叫做人道主義。因為救的不是那個『一』，而是救的那個『人』。」這種人道主義的昂 揚，是人類文明一大進程。由於人道主義的出現，率獸食人的社會才絕跡於人間。由於人道 主義的覺醒，以人祭天的犧牲才消弭於人世。 根據上文，下列選項何者屬於人道主義的表現？', '["國際紅十字會對受害者提供保護及救助", "國際貨幣基金組織長期致力於穩定匯率", "無國界醫生在衝突地區提供醫療及物資", "世界展望會幫助貧困兒童以及進行賑災 歐洲聯盟促進社會經濟發展及公民覺醒"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:26+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "513", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00514', 'elementary-acfc4025', 'elementary-acfc4025-moex-112-34c7f7f6', 'sub-elementary-acfc4025-02', NULL, 'single_choice', '「知識分子既不是調解者，也不是建立共識的人，而是全身投注於批評意識，不願接受簡單 的處方、現成的陳腔濫調，或平和寬容的肯定權勢者的說法或作法。他總是時時維持著警覺 狀態，永遠不讓似是而非的事物或約定俗成的觀念牽著鼻子走。」 根據上文，下列選項何者符合知識分子的特質？', '["不落俗套", "左右逢源", "通才碩學", "韜光養晦 慎思明辨"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:26+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "513", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00515', 'elementary-acfc4025', 'elementary-acfc4025-moex-112-34c7f7f6', 'sub-elementary-acfc4025-02', NULL, 'single_choice', '「心理學的研究上有個現象叫做『破窗效應』，就是說，一個房子如果窗戶破了，沒有人去 修補，隔不久，其它的窗戶也會莫名其妙的被人打破；一面牆，如果出現一些塗鴉沒有清洗 掉，很快地，牆上就布滿了亂七八糟，不堪入目的東西。一個很乾淨的地方，人會不好意思 丟垃圾，但是一旦地上有垃圾出現之後，人就會毫不猶疑地拋，絲毫不覺羞愧。這真是很奇 怪的現象。」 根據上文，下列選項何者符合「破窗效應」的觀點？', '["管理時必須有統一的要求與準則", "防微杜漸是預防問題的手段之一", "人們很容易仿效他人不良的行為", "組織中引進競爭者可以激發活力 環境對人的行為具有強烈誘導性"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:26+00:00", "source_pdf_sha1": "956a0c9fbe15", "answer_pdf_sha1": "1a6f54ad7459", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "513", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00516', 'elementary-acfc4025', 'elementary-acfc4025-moex-112-35395ec3', 'sub-elementary-acfc4025-03', NULL, 'single_choice', '電阻值為3.6 MΩ5%的電阻器，其四環色碼如何表示？', '["紅紫綠金", "橙藍綠金", "紅藍綠金", "橙紫綠銀"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:26+00:00", "source_pdf_sha1": "1b2216fefc66", "answer_pdf_sha1": "31c3e14e63c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "513", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基本電學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00517', 'elementary-acfc4025', 'elementary-acfc4025-moex-112-35395ec3', 'sub-elementary-acfc4025-03', NULL, 'single_choice', '使10公克水的溫度升高1℃，其所需的電能為多少焦耳？', '["42", "4.2", "2.4", "0.24"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:26+00:00", "source_pdf_sha1": "1b2216fefc66", "answer_pdf_sha1": "31c3e14e63c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "513", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基本電學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00518', 'elementary-acfc4025', 'elementary-acfc4025-moex-112-35395ec3', 'sub-elementary-acfc4025-03', NULL, 'single_choice', '如圖所示，將一個5歐姆（Ω）電阻與兩個並聯之18歐姆電阻相串聯，則流經5歐姆電阻之電流為 多少安培？ 5Ω 28V 18Ω 18Ω', '["2/3", "6/5", "3/2", "2"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:26+00:00", "source_pdf_sha1": "1b2216fefc66", "answer_pdf_sha1": "31c3e14e63c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "513", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基本電學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00519', 'elementary-acfc4025', 'elementary-acfc4025-moex-112-35395ec3', 'sub-elementary-acfc4025-03', NULL, 'single_choice', '有一電阻流過2安培電流，經過30秒總共消耗7200焦耳，此電阻所跨電壓為多少伏特？', '["100", "120", "240", "3600"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:26+00:00", "source_pdf_sha1": "1b2216fefc66", "answer_pdf_sha1": "31c3e14e63c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "513", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基本電學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL),
  ('elementary-acfc4025-moex-00520', 'elementary-acfc4025', 'elementary-acfc4025-moex-112-35395ec3', 'sub-elementary-acfc4025-03', NULL, 'single_choice', '將20歐姆、30歐姆、60歐姆三個電阻並聯後，其等效電阻為多少歐姆？', '["55", "20", "10", "5"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:26+00:00", "source_pdf_sha1": "1b2216fefc66", "answer_pdf_sha1": "31c3e14e63c7", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "513", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "基本電學大意", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "電子工程"}'::jsonb, NULL)
